func overallAverageOffers(accepted float64, completed float64) float64 {
	if accepted == 0 && completed == 0 {
		return 0
	}
	if accepted == 0 {
		return completed
	}
	if completed == 0 {
		return accepted
	}
	return (accepted + completed) / 2
}

